import{_ as e,o as t,c as s,O as r}from"./chunks/framework.0d5b6918.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/freelance-home-structure.md","filePath":"en/materials/freelance-home-structure.md","lastUpdated":1776344074000}'),n={name:"en/materials/freelance-home-structure.md"};function i(c,a,l,d,o,p){return t(),s("div",null,a[0]||(a[0]=[r('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Reading Path</p><h1>Three-Layer Cooperation Materials Structure and Suggested Reading Order</h1><div class="brand-hero__panel"><span class="brand-pill">Client Reading Path</span><strong>If you are evaluating whether ExecFabric is a good fit for cooperation, you do not need to read the whole website at once. The more efficient way is to judge it through the three material layers first, then decide whether to move into a formal discussion.</strong><p>This page explains which question each layer answers and which stage it fits best.</p></div><p class="brand-lead"> The current recommendation is to fix the cooperation materials into three layers: <strong>the background overview page, the resume and capability page, and the service-package and delivery page</strong>. That lets you judge directional fit quickly first, then continue into delivery background, service boundary, and formal cooperation mode. </p><div class="brand-chip-list"><span class="brand-chip">quick first judgment</span><span class="brand-chip">verify background next</span><span class="brand-chip">delivery last</span><span class="brand-chip">resume and capability page</span><span class="brand-chip">service-package and delivery page</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./founder-card.html">Start with Background Overview</a><a class="cta-button" href="./resume-public.html">View Projects and Resume</a><a class="cta-button" href="./service-packages.html">View Service Packages and Delivery</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // READING PATH</span><span>MAT 09</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">step_1</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">overview</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">step_2</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">background_check</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">step_3</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">delivery_scope</span></span></div><div class="matrix-panel__callout">READ WHAT YOU NEED FIRST</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">phase</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">first contact</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">phase</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">background check</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">phase</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">project discussion</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><a class="brand-link-card" href="./founder-card.html"><span>Layer 01</span><strong>Background Overview</strong><p>This corresponds to <code>founder-card</code>. It fits the first contact, when the main goal is to judge who is building this, what the current mainline is, and whether it is worth learning more.</p></a><a class="brand-link-card" href="./resume-public.html"><span>Layer 02</span><strong>Projects and Resume</strong><p>This corresponds to <code>resume-public</code>. It fits cases where you need a deeper check of the technical background, project history, and capability range.</p></a><a class="brand-link-card" href="./service-packages.html"><span>Layer 03</span><strong>Service Packages and Delivery</strong><p>This corresponds to <code>service-packages</code>. It fits the stage where a project conversation is already real and the focus is how to start, how to close, and how delivery works.</p></a></section><section class="brand-card"><p class="brand-kicker">Three Layers</p><h2>Cooperation materials are fixed into three layers</h2><table class="cooperation-start-table"><thead><tr><th>Layer</th><th>Suggested page</th><th>What it answers</th><th>Best stage to read it</th></tr></thead><tbody><tr><td>Background overview page</td><td><a href="./founder-card.html">founder-card</a></td><td>Who is building this, what the current mainline is, and which kind of scenario fits as a first entry</td><td>At first contact</td></tr><tr><td>Resume and capability page</td><td><a href="./resume-public.html">resume-public</a></td><td>What has been done before, what the technical and delivery background looks like, and whether the project history is credible</td><td>When background needs to be verified</td></tr><tr><td>Service-package and delivery page</td><td><a href="./service-packages.html">service-packages</a> + <a href="../product/deliverables.html">Customer Delivery Docs &amp; Entry Points</a></td><td>How the project starts, how it closes, what is included in delivery, and whether it is ready for formal discussion</td><td>When the conversation enters requirements or budget</td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Reading Order</p><h2>Three common reading orders</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>1. When learning it for the first time</h3><ol class="brand-list"><li>Start with <a href="./founder-card.html">founder-card</a> to judge the direction and boundary quickly.</li><li>If deeper background verification is needed, continue with <a href="./resume-public.html">resume-public</a>.</li><li>If the conversation has already become a project discussion, continue with <a href="./service-packages.html">service-packages</a> and the <a href="../product/deliverables.html">Customer Delivery Docs &amp; Entry Points page</a>.</li></ol></article><article class="brand-card brand-card--nested"><h3>2. When background verification comes first</h3><ol class="brand-list"><li>Start with <a href="./resume-public.html">resume-public</a> to confirm the technical and project background.</li><li>Then add <a href="./founder-card.html">founder-card</a> to understand the overall direction and fitting entry scenarios.</li><li>If the discussion has already reached project boundaries, continue with <a href="./service-packages.html">service-packages</a>.</li></ol></article><article class="brand-card brand-card--nested"><h3>3. When the project discussion is already real</h3><ol class="brand-list"><li>Start with <a href="./service-packages.html">service-packages</a> to confirm the cooperation mode and the phase-one scope.</li><li>Then read the <a href="../product/deliverables.html">Customer Delivery Docs &amp; Entry Points page</a> to confirm what is handed over and through which entry points.</li><li>If source-code transfer, private deployment, or licensing boundary is involved, continue with <a href="./source-delivery-boundaries.html">Source Delivery and Licensing Boundary</a>.</li></ol></article></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Quick Rule</p><h2>If you only want a quick first judgment</h2><ul class="brand-list"><li>At first contact: start with the background overview page.</li><li>When background needs verification: continue with the resume and capability page.</li><li>When the project discussion becomes real: continue with the service-package and delivery page.</li></ul></article><article class="brand-card"><p class="brand-kicker">Common Mistakes</p><h2>What is not recommended</h2><ul class="brand-list"><li>Reading the whole website from top to bottom on first contact. The judgment cost becomes too high.</li><li>Already being in project discussion but still reading only background pages, without service packages and delivery boundaries.</li><li>Reading only the delivery page without checking technical background and project history.</li><li>Stopping at one single entry and drawing conclusions too early, which makes key information easy to miss.</li></ul></article></section></div>',1)]))}const m=e(n,[["render",i]]);export{u as __pageData,m as default};
